INSERT INTO country_attribute_values (country_id, attribute_definition_id, value_json, source_ref)
SELECT countries.id, definitions.id, payload.value_json, payload.source_ref
FROM payload
INNER JOIN countries ON countries.iso3 = payload.iso3
INNER JOIN country_attribute_definitions AS definitions ON definitions.key = payload.attribute_key;

COMMIT;
